local cjson = require "cjson"
local xml = require "xml"

local _M = {}

local function read_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    
    if not body then
        local body_file = ngx.req.get_body_file()
        if body_file then
            local file = io.open(body_file, "r")
            if file then
                body = file:read("*all")
                file:close()
            end
        end
    end
    
    return body
end

local function xml_to_table(node)
    if type(node) ~= "table" then
        return node
    end
    
    local result = {}
    
    for i, child in ipairs(node) do
        if type(child) == "table" then
            local tag = child.tag or child[0]
            local value = xml_to_table(child)
            
            if tag then
                if result[tag] then
                    if type(result[tag]) ~= "table" or result[tag].tag then
                        result[tag] = {result[tag]}
                    end
                    table.insert(result[tag], value)
                else
                    result[tag] = value
                end
            end
        elseif type(child) == "string" then
            if #node == 1 then
                return child
            end
        end
    end
    
    for k, v in pairs(node) do
        if type(k) == "string" and k ~= "tag" and k ~= 0 then
            result["@" .. k] = v
        end
    end
    
    if next(result) == nil and #node == 0 then
        return node[1] or ""
    end
    
    return result
end

local function parse_xml_with_entities(xml_string)
    if not xml_string or xml_string == "" then
        return nil, "Empty XML body"
    end
    
    local success, parsed = pcall(function()
        return xml.load(xml_string)
    end)
    
    if not success then
        return nil, "XML parsing error: " .. tostring(parsed)
    end
    
    return parsed
end

local function extract_soap_body(parsed_xml)
    local data = xml_to_table(parsed_xml)
    
    if data["soap:Envelope"] or data["SOAP-ENV:Envelope"] or data.Envelope then
        local envelope = data["soap:Envelope"] or data["SOAP-ENV:Envelope"] or data.Envelope
        local body = envelope["soap:Body"] or envelope["SOAP-ENV:Body"] or envelope.Body
        
        if body then
            return body
        end
    end
    
    return data
end

function _M.parse_xml_request()
    local body = read_request_body()
    
    if not body then
        return nil, "No request body found"
    end
    
    local parsed_xml, err = parse_xml_with_entities(body)
    if not parsed_xml then
        return nil, err
    end
    
    local soap_body = extract_soap_body(parsed_xml)
    
    return soap_body
end

function _M.get_element_value(data, path)
    local parts = {}
    for part in string.gmatch(path, "[^.]+") do
        table.insert(parts, part)
    end
    
    local current = data
    for _, part in ipairs(parts) do
        if type(current) ~= "table" then
            return nil
        end
        current = current[part]
        if current == nil then
            return nil
        end
    end
    
    return current
end

function _M.handle_soap_request()
    local soap_data, err = _M.parse_xml_request()
    
    if not soap_data then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.header["Content-Type"] = "application/xml"
        ngx.say('<?xml version="1.0" encoding="UTF-8"?>')
        ngx.say('<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">')
        ngx.say('  <soap:Body>')
        ngx.say('    <soap:Fault>')
        ngx.say('      <faultcode>soap:Client</faultcode>')
        ngx.say('      <faultstring>' .. (err or "Invalid XML") .. '</faultstring>')
        ngx.say('    </soap:Fault>')
        ngx.say('  </soap:Body>')
        ngx.say('</soap:Envelope>')
        return
    end
    
    return soap_data
end

function _M.create_soap_response(data)
    ngx.header["Content-Type"] = "application/xml"
    ngx.say('<?xml version="1.0" encoding="UTF-8"?>')
    ngx.say('<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">')
    ngx.say('  <soap:Body>')
    
    if type(data) == "string" then
        ngx.say('    ' .. data)
    else
        ngx.say('    <Response>')
        ngx.say('      <Status>Success</Status>')
        ngx.say('      <Data>' .. cjson.encode(data) .. '</Data>')
        ngx.say('    </Response>')
    end
    
    ngx.say('  </soap:Body>')
    ngx.say('</soap:Envelope>')
end

function _M.process_request()
    local soap_data = _M.handle_soap_request()
    
    if not soap_data then
        return
    end
    
    ngx.ctx.soap_data = soap_data
    ngx.ctx.parsed_xml = true
    
    return soap_data
end

